#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[501], t[501];
        scanf("%s", s);
        scanf("%s", t);
        int len = strlen(s);
        int count = 0;
        for (int i = 0; i < len; i++) {
            if (s[i] != t[i]) {
                count++;
            }
        }
        if (count == 0 || count == 2) {
            printf("B\n");
        } else {
            printf("A\n");
        }
    }
    return 0;
}

