code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            String t = sc.next();
            int len = s.length();
            int count = 0;
            for (int i = 0; i < len; i++) {
                if (s.charAt(i) != t.charAt(i)) {
                    count++;
                }
            }
            if (count == 0 || count == 2) {
                System.out.println("B");
            } else {
                System.out.println("A");
            }
        }
    }
}

